external_knowledge:
- A 'trip' refers to the journey of a bike from one station to another; 
- The 'average trip duration' is the total duration of all trips from a station divided by the number of trips; 
- The 'maintenance cost' refers to the cost of maintaining a bike.

sql:
SELECT total_trips
FROM usage_stats
ORDER BY total_trips DESC;

SELECT total_trips
FROM usage_stats
WHERE station_id = 0;
